scwin.f_Retrieve = async function () {
  await scwin.lfn_SetGridFormat();

  //날짜 체크 start---------------------------------------
  let stDt = ica_FromDate.getValue();
  let endDt = ica_ToDate.getValue();
  if (!(await $c.gus.cfIsAfterDate($p, stDt, endDt))) {
    await $c.win.alert($p, $c.data.getMessage($p, MSG_CM_ERR_039)); // 시작일자를 종료일 이전으로 선택[입력]하여 주십시오.
    ica_FromDate.focus();
    return;
  }
  //날짜 체크 end---------------------------------------	
  let arrSort = gr_oilUnitPrice.getSortableStatus();
  for (var i = 0; i < arrSort.length; i++) {
    if (arrSort[i].colID == "stdDt") {
      console.log("==============arrSort[" + i + "]" + arrSort[i].colID + ", sortOrder:" + arrSort[i].sortOrder);
      scwin.sortId = arrSort[i].colID;
      scwin.sortOrder = arrSort[i].sortOrder;
      // ds_oilUnitPrice.sort("stdDt", arrSort[i].sortOrder);
    }
  }
  $c.sbm.execute($p, sbm_retrieve);
};
scwin.sbm_retrieve_submitdone = async function (e) {
  ds_saveOilUnitPrice.removeAll();
  ds_firstRowCodeSetting.removeAll();
  scwin.lfn_firstRowCodeSetting(); //첫번째 row의 거래처번호 setting

  totalRows.setValue(ds_oilUnitPrice.getRowCount());
  if (ds_oilUnitPrice.getRowCount() == 0) {
    await $c.win.alert($p, MSG_CM_WRN_002);
  } else {
    // ds_oilUnitPrice.sort("stdDt", 0);
    if (scwin.sortId != "") {
      console.log("==============scwin.sortId:" + scwin.sortId + ", scwin.sortOrder:" + scwin.sortOrder);
      let order = 2;
      if (scwin.sortOrder == -1) {
        order = 1;
      } else if (scwin.sortOrder == 1) {
        order = 0;
      }
      ds_oilUnitPrice.sort("stdDt", order);
    }
    scwin.sortId = "";
    scwin.sortOrder = 0;
  }
};

//-------------------------------------------------------------------------
// 첫번째 row 거래처번호 setting하기
//-------------------------------------------------------------------------
scwin.lfn_firstRowCodeSetting = async function () {
  if (ds_oilUnitPrice.getRowCount() == 0) {
    var rowIndex = ds_firstRowCodeSetting.insertRow();
    await scwin.lfn_oilComapnyCnt();
    if (ds_oilCompanyCnt.getRowCount() > 0) {
      for (let i = 0; i < ds_oilCompanyCnt.getRowCount(); i++) {
        let lgs_code = ds_oilCompanyCnt.getCellData(i, "code");
        let vClntNo = "clntNo" + (i + 1);
        ds_firstRowCodeSetting.setCellData(rowIndex, vClntNo.toString(), lgs_code);
      }
    }
  } else {
    //row갯수 만큼,, 루프돌리기
    for (let j = 0; j < ds_oilUnitPrice.getRowCount(); j++) {
      var rowIndex = ds_firstRowCodeSetting.insertRow();
      await scwin.lfn_oilComapnyCnt();
      if (ds_oilCompanyCnt.getRowCount() > 0) {
        for (let i = 0; i < ds_oilCompanyCnt.getRowCount(); i++) {
          let lgs_code = ds_oilCompanyCnt.getCellData(i, "code");
          let vClntNo = "clntNo" + (i + 1);
          ds_firstRowCodeSetting.setCellData(j, vClntNo.toString(), lgs_code);
        }
      }
    }
  }
};

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
  if (ds_oilUnitPrice.getModifiedIndex().length == 0) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_001, ['유류단가 그리드']); //변경된 정보가 없습니다.
    return;
  }
  if (!(await $c.gus.cfValidate($p, gr_oilUnitPrice, null, true))) return;
  await scwin.lfn_checkValue();
  if (scwin.isDate != null) {
    //당월 체크    
    if (!(await scwin.f_chkMonth())) {
      ds_saveOilUnitPrice.removeAll();
      return;
    }
  }
  if (ds_saveOilUnitPrice.getRowCount() == 0) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_041, ['[입력된 유류단가가 없는 경우]', '저장']); //"@은(는) @할 수 없습니다.";
    return;
  }
  if ((await $c.win.confirm($p, MSG_CM_CRM_001)) == true) {
    //저장하시겠습니까?
    $c.sbm.execute($p, sbm_saveOilPrice);
  } else {
    scwin.f_Retrieve();
    ds_saveOilUnitPrice.removeAll();
  }
};
scwin.sbm_saveOilPrice_submitdone = async function (e) {
  if (e.responseJSON.resultDataSet[0].Code < 0) return;
  if (e.responseJSON.resultDataSet[0].Code == 0) {
    await $c.gus.cfAlertMsg($p, MSG_CM_INF_001); // 성공적으로 저장하였습니다
    scwin.f_Retrieve();
    ds_saveOilUnitPrice.removeAll();
  }
};

//-------------------------------------------------------------------------
// 당월 체크
//-------------------------------------------------------------------------
scwin.f_chkMonth = async function () {
  let chkRowStatus = "";
  let yyyymmdd = "";
  let yyyymm = "";

  //row갯수 만큼,, 루프돌리기
  for (let j = 0; j < ds_saveOilUnitPrice.getRowCount(); j++) {
    chkRowStatus = ds_saveOilUnitPrice.getRowStatus(j);
    yyyymmdd = ds_saveOilUnitPrice.getCellData(j, 'stdDt');
    yyyymm = scwin.lfn_GetMonth(scwin.isDate, 1, 1);
    if (chkRowStatus == "C" || chkRowStatus == "D" || chkRowStatus == "U") {
      if (yyyymm > yyyymmdd.substring(0, 6)) {
        await $c.win.alert($p, $c.data.getMessage($p, MSG_CM_ERR_041, ['기준일자의 해당 월에 대한 마감여부가 [마감중]또는 [마감완료]인 경우'], '저장')); //"@은(는) @할 수 없습니다.";
        return false;
      }
    }
  }
  return true;
};

