scwin.lfn_checkValue = async function () {
  ds_saveOilUnitPrice.removeAll();
  let cntUpdateRow = ds_oilUnitPrice.getRowCount();

  // row갯수 만큼,, 루프돌리기
  for (let j = 0; j < cntUpdateRow; j++) {
    let checkedOrgRowStatus = ds_oilUnitPrice.getRowStatus(j); // C, U, D, R

    // Insert
    if (checkedOrgRowStatus == "C") {
      await scwin.lfn_oilComapnyCnt();
      if (ds_oilCompanyCnt.getRowCount() > 0) {
        //column갯수 만큼,, 루프돌리기 
        for (let i = 0; i <= ds_oilCompanyCnt.getRowCount(); i++) {
          if (i == 0) {
            let org_clntNo = ds_oilUnitPrice.getCellData(j, "clntNo");
            let org_oilInUpr = ds_oilUnitPrice.getCellData(j, "oilInUpr");
            if (org_oilInUpr != null && org_oilInUpr != 0) {
              let newRow = ds_saveOilUnitPrice.insertRow();
              ds_saveOilUnitPrice.setCellData(newRow, "stdDt", ds_oilUnitPrice.getCellData(j, "stdDt"));
              ds_saveOilUnitPrice.setCellData(newRow, "oilCoClntNo", org_clntNo);
              ds_saveOilUnitPrice.setCellData(newRow, "oilInUpr", org_oilInUpr);
              ds_saveOilUnitPrice.modifyRowStatus(newRow, "C"); // Insert
            }
          } else {
            let org_oilInUpr2 = ds_oilUnitPrice.getCellData(j, "oilInUpr" + i);
            if (org_oilInUpr2 != null && org_oilInUpr2 != 0) {
              let newRow = ds_saveOilUnitPrice.insertRow();
              ds_saveOilUnitPrice.setCellData(newRow, "stdDt", ds_oilUnitPrice.getCellData(j, "stdDt"));
              ds_saveOilUnitPrice.setCellData(newRow, "oilCoClntNo", ds_oilUnitPrice.getCellData(j, "clntNo" + i));
              ds_saveOilUnitPrice.setCellData(newRow, "oilInUpr", org_oilInUpr2);
              ds_saveOilUnitPrice.modifyRowStatus(newRow, "C"); // Insert
            }
          }
        } // for-end 
      } else {
        let org_clntNo = ds_oilUnitPrice.getCellData(j, "clntNo");
        let org_oilInUpr = ds_oilUnitPrice.getCellData(j, "oilInUpr");
        if (org_oilInUpr != null && org_oilInUpr != 0) {
          let newRow = ds_saveOilUnitPrice.insertRow();
          ds_saveOilUnitPrice.setCellData(newRow, "stdDt", ds_oilUnitPrice.getCellData(j, "stdDt"));
          ds_saveOilUnitPrice.setCellData(newRow, "oilCoClntNo", org_clntNo);
          ds_saveOilUnitPrice.setCellData(newRow, "oilInUpr", org_oilInUpr);
          ds_saveOilUnitPrice.modifyRowStatus(newRow, "C");
        }
      }
    } else if (checkedOrgRowStatus == "D") {
      await scwin.lfn_oilComapnyCnt();
      if (ds_oilCompanyCnt.getRowCount() > 0) {
        //column갯수 만큼,, 루프돌리기 
        for (let i = 0; i <= ds_oilCompanyCnt.getRowCount(); i++) {
          if (i == 0) {
            let org_clntNo = ds_oilUnitPrice.getCellData(j, "clntNo");
            let org_inUprSeq = ds_oilUnitPrice.getCellData(j, "inUprSeq");
            let org_oilInUpr = ds_oilUnitPrice.getCellData(j, "oilInUpr");
            let newRow = ds_saveOilUnitPrice.insertRow();
            //기준일자,순번,거래처번호,유류입고단가
            ds_saveOilUnitPrice.setCellData(newRow, "stdDt", ds_oilUnitPrice.getCellData(j, "stdDt"));
            ds_saveOilUnitPrice.setCellData(newRow, "inUprSeq", org_inUprSeq);
            ds_saveOilUnitPrice.setCellData(newRow, "oilCoClntNo", org_clntNo);
            ds_saveOilUnitPrice.setCellData(newRow, "oilInUpr", org_oilInUpr);
            ds_saveOilUnitPrice.modifyRowStatus(newRow, "D"); // Delete
          } else {
            let org_oilInUpr2 = ds_oilUnitPrice.getCellData(j, "oilInUpr" + i);
            let newRow = ds_saveOilUnitPrice.insertRow();
            //기준일자,순번,거래처번호,유류입고단가
            ds_saveOilUnitPrice.setCellData(newRow, "stdDt", ds_oilUnitPrice.getCellData(j, "stdDt"));
            ds_saveOilUnitPrice.setCellData(newRow, "inUprSeq", ds_oilUnitPrice.getCellData(j, "inUprSeq" + i));
            ds_saveOilUnitPrice.setCellData(newRow, "oilCoClntNo", ds_oilUnitPrice.getCellData(j, "clntNo" + i));
            ds_saveOilUnitPrice.setCellData(newRow, "oilInUpr", org_oilInUpr2);
            ds_saveOilUnitPrice.modifyRowStatus(newRow, "D"); // Delete
          }
        }
      } else {
        let org_clntNo = ds_oilUnitPrice.getCellData(j, "clntNo");
        let org_inUprSeq = ds_oilUnitPrice.getCellData(j, "inUprSeq");
        let org_oilInUpr = ds_oilUnitPrice.getCellData(j, "oilInUpr");
        let newRow = ds_saveOilUnitPrice.insertRow();
        //기준일자,순번,거래처번호,유류입고단가	
        ds_saveOilUnitPrice.setCellData(newRow, "stdDt", ds_oilUnitPrice.getCellData(j, "stdDt"));
        ds_saveOilUnitPrice.setCellData(newRow, "inUprSeq", org_inUprSeq);
        ds_saveOilUnitPrice.setCellData(newRow, "oilCoClntNo", org_clntNo);
        ds_saveOilUnitPrice.setCellData(newRow, "oilInUpr", org_oilInUpr);
        ds_saveOilUnitPrice.modifyRowStatus(newRow, "D"); // Delete
      }
    } else if (checkedOrgRowStatus == "U") {
      await scwin.lfn_oilComapnyCnt();
      if (ds_oilCompanyCnt.getRowCount() > 0) {
        //column갯수 만큼,, 루프돌리기 
        for (let i = 0; i <= ds_oilCompanyCnt.getRowCount(); i++) {
          if (i == 0) {
            let org_clntNo = ds_oilUnitPrice.getCellData(j, "clntNo");
            let org_inUprSeq = ds_oilUnitPrice.getCellData(j, "inUprSeq");
            let oilInUpr = ds_oilUnitPrice.getCellData(j, "oilInUpr");
            let orgOilInUpr = ds_oilUnitPrice.getOriginalCellData(j, "oilInUpr");
            if (orgOilInUpr != oilInUpr) {
              let newRow = ds_saveOilUnitPrice.insertRow();
              ds_saveOilUnitPrice.setCellData(newRow, "stdDt", ds_oilUnitPrice.getCellData(j, "stdDt"));
              ds_saveOilUnitPrice.setCellData(newRow, "inUprSeq", org_inUprSeq);
              ds_saveOilUnitPrice.setCellData(newRow, "oilCoClntNo", org_clntNo);
              ds_saveOilUnitPrice.setCellData(newRow, "oilInUpr", oilInUpr);
              if (orgOilInUpr == 0 || orgOilInUpr == null) {
                ds_saveOilUnitPrice.modifyRowStatus(newRow, "C"); // Insert
              } else {
                ds_saveOilUnitPrice.modifyRowStatus(newRow, "U"); // Update
              }
              if (oilInUpr == 0 || oilInUpr == null) {
                ds_saveOilUnitPrice.modifyRowStatus(newRow, "D"); // Delete
              }
            }
          } else {
            let oilInUpr2 = ds_oilUnitPrice.getCellData(j, "oilInUpr" + i);
            let orgOilInUpr2 = ds_oilUnitPrice.getOriginalCellData(j, "oilInUpr" + i);
            if (orgOilInUpr2 != oilInUpr2) {
              let newRow = ds_saveOilUnitPrice.insertRow();
              ds_saveOilUnitPrice.setCellData(newRow, "stdDt", ds_oilUnitPrice.getCellData(j, "stdDt"));
              ds_saveOilUnitPrice.setCellData(newRow, "inUprSeq", ds_oilUnitPrice.getCellData(j, "inUprSeq" + i));
              ds_saveOilUnitPrice.setCellData(newRow, "oilCoClntNo", ds_oilUnitPrice.getCellData(j, "clntNo" + i));
              ds_saveOilUnitPrice.setCellData(newRow, "oilInUpr", oilInUpr2);
              if (orgOilInUpr2 == 0 || orgOilInUpr2 == null) {
                ds_saveOilUnitPrice.modifyRowStatus(newRow, "C");
              } else {
                ds_saveOilUnitPrice.modifyRowStatus(newRow, "U");
              }
              if (oilInUpr2 == 0 || oilInUpr2 == null) {
                ds_saveOilUnitPrice.modifyRowStatus(newRow, "D");
              }
            }
          }
        }
      } else {
        let org_clntNo = ds_oilUnitPrice.getCellData(j, "clntNo");
        let org_inUprSeq = ds_oilUnitPrice.getCellData(j, "inUprSeq");
        let oilInUpr = ds_oilUnitPrice.getCellData(j, "oilInUpr");
        let orgOilInUpr = ds_oilUnitPrice.getOriginalCellData(j, "oilInUpr");
        if (orgOilInUpr != oilInUpr) {
          let newRow = ds_saveOilUnitPrice.insertRow();
          ds_saveOilUnitPrice.setCellData(newRow, "stdDt", ds_oilUnitPrice.getCellData(j, "stdDt"));
          ds_saveOilUnitPrice.setCellData(newRow, "inUprSeq", org_inUprSeq);
          ds_saveOilUnitPrice.setCellData(newRow, "oilCoClntNo", org_clntNo);
          ds_saveOilUnitPrice.setCellData(newRow, "oilInUpr", oilInUpr);
          if (orgOilInUpr == 0 || orgOilInUpr == null) {
            ds_saveOilUnitPrice.modifyRowStatus(newRow, "C"); // Insert
          } else {
            ds_saveOilUnitPrice.modifyRowStatus(newRow, "U"); // Update
          }
          if (oilInUpr == 0 || oilInUpr == null) {
            ds_saveOilUnitPrice.modifyRowStatus(newRow, "D"); // Delete
          }
        }
      }
    }
  } //for-end
};

