//-------------------------------------------------------------------------
scwin.f_DelRow = async function () {
  let row = ds_oilUnitPrice.getRowPosition();
  if (scwin.isDate != null) {
    let yyyymmdd = ds_oilUnitPrice.getCellData(row, 'stdDt');
    let yyyymm = scwin.lfn_GetMonth(scwin.isDate, 1, 1);
    if (yyyymm > yyyymmdd.substring(0, 6)) {
      await $c.win.alert($p, $c.data.getMessage($p, MSG_CM_ERR_041, ['기준일자의 해당 월에 대한 마감여부가 [마감중]또는 [마감완료]인 경우'], '삭제'));
      return;
    } else if (ds_oilUnitPrice.getRowStatus(row) == "C") {
      ds_oilUnitPrice.removeRow(row);
    } else {
      ds_oilUnitPrice.deleteRow(row);
    }
  } else {
    ds_oilUnitPrice.deleteRow(row);
  }
  gr_oilUnitPrice.setFocusedCell(row, 'stdDt');
};

//------------------------------------------------------------------------- 
// 해당월에서 iBase만큼 차이가 나는 월을 구한다.
//------------------------------------------------------------------------- 
scwin.lfn_GetMonth = function (sYearMonth, iBase, iMod) {
  let sYear = parseFloat(sYearMonth.substring(0, 4));
  let sMonth = parseFloat(sYearMonth.substring(4, 6));
  let sResult;
  sMonth = sMonth + iBase;
  if (sMonth >= 13) {
    sMonth = sMonth - 12;
    sYear = sYear + 1;
  } else if (sMonth <= 0) {
    sMonth = sMonth + 12;
    sYear = sYear - 1;
  }
  if (sMonth < 10) sResult = sYear.toString() + '0' + sMonth.toString();else sResult = sYear.toString() + sMonth.toString();
  return sResult;
};

