scwin.sbm_oilCompanyCnt_submitdone = function (e) {
  let companyCount = ds_oilCompanyCnt.getRowCount();
  if (companyCount >= 1) {
    for (let i = 1; i <= companyCount; i++) {
      let colIdSeq = "h_inUprSeq" + i;
      let colIdClnt = "h_clntNo" + i;
      let colIdUpr = "h_oilInUpr" + i;
      let lgs_name = ds_oilCompanyCnt.getCellData(i - 1, "name");
      gr_oilUnitPrice.setColumnVisible("oilInUpr" + i, true);
      gr_oilUnitPrice.setHeaderValue(colIdUpr, lgs_name);
      gr_oilUnitPrice.setColumnVisible("inUprSeq" + i, false);
      gr_oilUnitPrice.setColumnVisible("clntNo" + i, false);
    }
  }
};
scwin.f_dateFormat = function (data) {
  if (data == null || data === "") {
    return "";
  }
  let strData = data.toString().trim();
  if (strData.length === 8) {
    // 8자리인 경우
    let year = strData.substring(0, 4);
    let month = strData.substring(4, 6);
    let day = strData.substring(6, 8);
    return year + "/" + month + "/" + day;
  } else if (strData.length === 6) {
    // 6자리인 경우
    let year = strData.substring(0, 4);
    let month = strData.substring(4, 6);
    return year + "/" + month + "/";
  } else {
    return strData;
  }
};
