scwin.gr_oilUnitPrice_onafteredit = async function (rowIndex, columnIndex, value) {
  let colid = gr_oilUnitPrice.getColumnID(columnIndex);
  if (scwin.isDate != null) {
    if (colid == "stdDt") {
      let yyyymmdd = ds_oilUnitPrice.getCellData(rowIndex, "stdDt");
      let yyyymm = scwin.lfn_GetMonth(scwin.isDate, 1, 1);
      if (yyyymm > yyyymmdd.substring(0, 6)) {
        await $c.win.alert($p, $c.data.getMessage($p, MSG_CM_ERR_041, ['기준일자의 해당 월에 대한 마감여부가 [마감중]또는 [마감완료]인 경우'], '입력'));
        ds_oilUnitPrice.setCellData(rowIndex, "stdDt", yyyymm);
        return;
      }
    }
  }
};

//-------------------------------------------------------------------------
// Grid 셀 클릭시 발생 이벤트
//-------------------------------------------------------------------------
scwin.gr_oilUnitPrice_oncellclick = function (rowIndex, columnIndex, columnId) {
  let chkRowStatus = ds_oilUnitPrice.getRowStatus(rowIndex);
  if (chkRowStatus == "C") {
    gr_oilUnitPrice.setRowReadOnly(rowIndex, false);
  } else {
    if (gr_oilUnitPrice.getColumnID(columnIndex) == "stdDt") {
      gr_oilUnitPrice.setCellReadOnly(rowIndex, "stdDt", true); // f_EditNone
    }
    gr_oilUnitPrice.setRowReadOnly(rowIndex, true);
    if (scwin.isDate != null) {
      var yyyymmdd = ds_oilUnitPrice.getCellData(rowIndex, "stdDt");
      var yyyymm = scwin.lfn_GetMonth(scwin.isDate, 1, 1);
      if (yyyymm > yyyymmdd.substring(0, 6)) {
        gr_oilUnitPrice.setRowReadOnly(rowIndex, true);
      } else {
        gr_oilUnitPrice.setRowReadOnly(rowIndex, false);
      }
    }
  }
  // 행삭제인 경우 편집불가
  if (chkRowStatus == "D") {
    gr_oilUnitPrice.setRowReadOnly(rowIndex, true);
  }
};
